#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
CI MAXN=1e6+5;
int a[MAXN],n,m,x;
int find(int k){
    int l=1,r=n,ans=-1;
    while(l<=r)
	{
        int mid=(l+r)>>1;
        if(a[mid]==k)
		{
            ans=mid;
			r=mid-1;
        }
		else if(a[mid]>k) r=mid-1;
        else l=mid+1;
    }
    return ans;
}
int main(void){
	//freopen("find.in","r",stdin);
	//freopen("find.out","w",stdout);
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;++i)scanf("%d",a+i);
    for(int i=1;i<=m;++i)
	{
        scanf("%d",&x);
        printf("%d ",find(x));
    }
    return false;
}
